def process_large_file(file_path, chunk_size=1024):
    try:
        with open(file_path, 'r') as f:
            while True:
                data = f.read(chunk_size)
                if not data:
                    break
                # Process the chunk
                print(f"Processing {len(data)} bytes")
    except MemoryError:
        print("MemoryError caught during file processing.")

# Example usage
process_large_file('large_data.txt')

